/**
 * Generate Strapi firewall config.
 *
 * Data source: https://docs.strapi.io/cms/api/rest
 *
 * Strapi uses Bearer token authentication via API tokens.
 * The base URL is instance-specific (self-hosted).
 * Users must provide a STRAPI_BASE_URL variable.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.strapi.io/cms/api/rest";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLo";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Strapi REST API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:strapi",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const strapiFirewall = {",
    '  name: "strapi",',
    '  description: "Strapi CMS API",',
    "  placeholders: {",
    `    STRAPI_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "${{ vars.STRAPI_BASE_URL }}",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.STRAPI_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Strapi firewall config...");
  const ts = generateTypeScript();
  writeOutput("strapi", ts, import.meta.dirname);
}
